import{_ as i,o as a,c as t,ak as e}from"./chunks/framework.d_5_XLDx.js";const g=JSON.parse('{"title":"全网最全！6种方法解决 GitHub 国内由于 DNS 污染导致无法访问的问题","description":"","frontmatter":{"title":"全网最全！6种方法解决 GitHub 国内由于 DNS 污染导致无法访问的问题","createTime":"2025/02/27 10:07:16","permalink":"/article/jddtxrrw/","tags":["GitHub","DNS","VPN"]},"headers":[],"relativePath":"blog/ermao/文档/如何解决github无法访问.md","filePath":"blog/ermao/文档/如何解决github无法访问.md","lastUpdated":1769775157000}'),l={name:"blog/ermao/文档/如何解决github无法访问.md"};function n(o,s,r,h,p,d){return a(),t("div",null,[...s[0]||(s[0]=[e(`<p>GitHub 是一个面向开源及私有软件项目的托管平台，不管是行业大佬还是编程小白都可以在 GitHub 上交流学习，但是国内的 GitHub 访问被污染，导致无法正常访问。</p><p>本文通过 6 种方法解决 GitHub 访问被污染的问题。如果全部方法试用后仍然无法访问（概率极低），欢迎在下方评论，手把手帮你处理！</p><p>GitHub 的 DNS 污染问题通常表现为域名解析被劫持到错误的 IP 地址，导致无法正常访问。</p><p>浏览器报错如下：</p><p><strong>嗯… 无法访问此页面</strong></p><p><strong>github.com 响应时间太长</strong></p><p><img src="https://image.ermao.net/images/article/jddtxrrw/image.png" alt="github.com 响应时间太长"></p><hr><p>下面提供几个可行的方案共大家参考</p><h2 id="_1-手动修改-hosts-文件" tabindex="-1"><strong>1. 手动修改 Hosts 文件</strong> <a class="header-anchor" href="#_1-手动修改-hosts-文件" aria-label="Permalink to &quot;**1. 手动修改 Hosts 文件**&quot;">​</a></h2><p>通过直接绑定 GitHub 域名的正确 IP 地址，绕过 DNS 解析污染。<br><strong>步骤</strong>：</p><ol><li><p><strong>获取最新的 GitHub 域名 IP</strong>：</p><ul><li>访问 <a href="https://www.ipaddress.com/" target="_blank" rel="noreferrer">IPAddress.com</a> 查询以下域名的当前 IP： <ul><li><code>github.com</code></li><li><code>assets-cdn.github.com</code></li><li><code>github.global.ssl.fastly.net</code></li><li><code>api.github.com</code></li><li><code>raw.githubusercontent.com</code></li></ul></li><li>或使用命令查询（需安装 <code>nslookup</code> 或 <code>dig</code>）：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nslookup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 使用 Google DNS 查询</span></span></code></pre></div></li></ul></li><li><p><strong>修改 Hosts 文件</strong>：</p><ul><li><strong>Windows</strong>： <ul><li>文件路径：<code>C:\\Windows\\System32\\drivers\\etc\\hosts</code></li><li>右键用管理员权限编辑，添加以下内容：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># GitHub</span></span>
<span class="line"><span>140.82.113.3    github.com</span></span>
<span class="line"><span>185.199.108.153 assets-cdn.github.com</span></span>
<span class="line"><span>199.232.69.194  github.global.ssl.fastly.net</span></span></code></pre></div></li></ul></li><li><strong>macOS/Linux</strong>： <ul><li>文件路径：<code>/etc/hosts</code></li><li>终端输入 <code>sudo nano /etc/hosts</code>，添加上述内容。</li></ul></li></ul></li><li><p><strong>刷新 DNS 缓存</strong>：</p><ul><li>Windows：<code>ipconfig /flushdns</code></li><li>macOS/Linux：<code>sudo dscacheutil -flushcache</code> 或 <code>sudo systemd-resolve --flush-caches</code></li></ul></li></ol><hr><h2 id="_2-使用加密-dns-服务" tabindex="-1"><strong>2. 使用加密 DNS 服务</strong> <a class="header-anchor" href="#_2-使用加密-dns-服务" aria-label="Permalink to &quot;**2. 使用加密 DNS 服务**&quot;">​</a></h2><p>通过加密 DNS（如 DNS-over-HTTPS 或 DNS-over-TLS）避免解析被劫持。<br><strong>推荐方案</strong>：</p><ul><li><strong>Cloudflare DNS</strong>（<code>1.1.1.1</code>）或 <strong>Google DNS</strong>（<code>8.8.8.8</code>）： <ul><li>手动设置设备的 DNS 地址。</li></ul></li><li><strong>DNSCrypt 或 DoH/DoT 工具</strong>： <ul><li>使用 <a href="https://adguard-dns.io/" target="_blank" rel="noreferrer">AdGuard DNS</a>、<a href="https://nextdns.io/" target="_blank" rel="noreferrer">NextDNS</a> 等支持加密的 DNS 服务。</li></ul></li></ul><hr><h2 id="_3-使用代理或-vpn-终极大杀器" tabindex="-1"><strong>3. 使用代理或 VPN(终极大杀器)</strong> <a class="header-anchor" href="#_3-使用代理或-vpn-终极大杀器" aria-label="Permalink to &quot;**3. 使用代理或 VPN(终极大杀器)**&quot;">​</a></h2><p>通过代理或 VPN 完全绕过本地 DNS 污染。<br><strong>推荐工具</strong>：</p><ul><li><strong>Clash</strong>（支持规则分流，开源免费）</li><li><strong>Shadowsocks/V2Ray</strong>（需自建或购买节点）</li><li>商业 VPN（如 ExpressVPN、NordVPN）</li></ul><p>相关内容：</p><ul><li>📱 <a href="https://www.ermao.net/article/eh8f4n86/" target="_blank" rel="noreferrer">clash for Android</a></li><li>🖥 <a href="https://www.ermao.net/article/0gematwc/" target="_blank" rel="noreferrer">clash for Windows</a></li><li>🍎 <a href="https://www.ermao.net/article/z747kgjd/" target="_blank" rel="noreferrer">clash for iOS</a></li></ul><hr><h2 id="_4-使用-github-镜像站点" tabindex="-1"><strong>4. 使用 GitHub 镜像站点</strong> <a class="header-anchor" href="#_4-使用-github-镜像站点" aria-label="Permalink to &quot;**4. 使用 GitHub 镜像站点**&quot;">​</a></h2><p>访问 GitHub 的镜像服务，避开主域名污染。<br><strong>常用镜像</strong>：</p><ul><li><a href="https://ghproxy.com/" target="_blank" rel="noreferrer">GitHub 加速下载</a></li><li><a href="https://hub.fastgit.org/" target="_blank" rel="noreferrer">FastGit</a>（已停用，可寻找替代）</li></ul><hr><h2 id="_5-验证-dns-污染" tabindex="-1"><strong>5. 验证 DNS 污染</strong> <a class="header-anchor" href="#_5-验证-dns-污染" aria-label="Permalink to &quot;**5. 验证 DNS 污染**&quot;">​</a></h2><p>确认是否真的是 DNS 污染导致的问题：</p><ol><li>使用 <code>nslookup</code> 或 <code>dig</code> 查询域名：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nslookup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.8.8.8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 使用干净的 DNS 查询</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nslookup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 使用本地默认 DNS 查询</span></span></code></pre></div><ul><li>若结果不一致，说明存在 DNS 污染。</li></ul></li></ol><hr><h2 id="_6-清除本地-dns-缓存" tabindex="-1"><strong>6. 清除本地 DNS 缓存</strong> <a class="header-anchor" href="#_6-清除本地-dns-缓存" aria-label="Permalink to &quot;**6. 清除本地 DNS 缓存**&quot;">​</a></h2><ul><li><strong>Windows</strong>：<div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ipconfig /flushdns</span></span></code></pre></div></li><li><strong>macOS</strong>：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> killall</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -HUP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mDNSResponder</span></span></code></pre></div></li><li><strong>Linux</strong>：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nscd</span></span></code></pre></div></li></ul><hr><h2 id="注意事项" tabindex="-1"><strong>注意事项</strong> <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;**注意事项**&quot;">​</a></h2><ol><li><strong>IP 地址可能变化</strong>，需定期更新 Hosts 文件。</li><li><strong>优先使用 HTTPS</strong>，避免中间人攻击。</li><li>如果使用代理/VPN，确保节点未被 GitHub 封禁（如某些机场 IP 可能被限制）。</li></ol><hr><p>通过以上方法，可有效绕过 DNS 污染问题。若问题持续，可能是网络环境限制（如防火墙），需结合代理或 VPN 彻底解决。</p>`,38)])])}const u=i(l,[["render",n]]);export{g as __pageData,u as default};
